#include <iostream>
#include <stdexcept>
using namespace std;

int divide(int a, int b) {
    if (b == 0) {
        throw "Division by zero!";  // throw exception
    }
    return a / b;
}

int main() {
    int x = 10, y = 0, result;

    try {
        cout << "Attempting division..." << endl;
        result = divide(x, y);  // may throw
        cout << "Result: " << result << endl;
    }
    catch (const char* msg) {  // catch specific type
        cout << "Exception caught: " << msg << endl;
    }
    catch (...) {  // catch all
        cout << "Unknown exception caught" << endl;
    }

    cout << "Program continues..." << endl;
    return 0;
}

#include <iostream>
#include <stdexcept>
#include <vector>
using namespace std;

void processArray(vector<int> arr, int index) {
    try {
        if (index < 0)
            throw invalid_argument("Negative index");
        if (index >= arr.size())
            throw out_of_range("Index out of bounds");
        cout << "Value at " << index << ": " << arr[index] << endl;
    }
    catch (const out_of_range& e) {
        cout << "Out of range: " << e.what() << endl;
    }
    catch (const invalid_argument& e) {
        cout << "Invalid argument: " << e.what() << endl;
    }
    catch (const exception& e) {
        cout << "Standard exception: " << e.what() << endl;
    }
    catch (...) {
        cout << "Unknown exception occurred" << endl;
    }
}

int main() {
    vector<int> nums = {1, 2, 3, 4, 5};

    cout << "Test 1: Negative index" << endl;
    processArray(nums, -1);

    cout << "\nTest 2: Out of bounds" << endl;
    processArray(nums, 10);

    cout << "\nTest 3: Valid index" << endl;
    processArray(nums, 2);

    return 0;
}

#include <iostream>
#include <string>
#include <exception>
using namespace std;

// Custom exception class inheriting from std::exception
class BankException : public exception {
private:
    string message;
public:
    BankException(const string& msg) : message(msg) {}

    // Override what() method
    const char* what() const noexcept override {
        return message.c_str();
    }
};

class InsufficientFundsException : public BankException {
private:
    double balance;
    double withdrawal;
public:
    InsufficientFundsException(double bal, double withdr)
        : BankException("Insufficient funds"), balance(bal), withdrawal(withdr) {}

    double getBalance() const { return balance; }
    double getWithdrawal() const { return withdrawal; }
};

void withdraw(double& balance, double amount) {
    if (amount > balance)
        throw InsufficientFundsException(balance, amount);
    balance -= amount;
}

int main() {
    double balance = 1000.0;

    try {
        cout << "Attempting to withdraw 500..." << endl;
        withdraw(balance, 500);
        cout << "Success! New balance: " << balance << endl;

        cout << "\nAttempting to withdraw 2000..." << endl;
        withdraw(balance, 2000);
    }
    catch (const InsufficientFundsException& e) {
        cout << "Exception: " << e.what() << endl;
        cout << "Balance: " << e.getBalance() << ", Requested: " << e.getWithdrawal() << endl;
    }
    catch (const exception& e) {
        cout << "Exception: " << e.what() << endl;
    }

    return 0;
}

#include <iostream>
using namespace std;

class ResourceHandler {
private:
    string name;
public:
    ResourceHandler(const string& n) : name(n) {
        cout << "Constructor: " << name << " created" << endl;
    }
    ~ResourceHandler() {
        cout << "Destructor: " << name << " destroyed" << endl;
    }
    void doWork() {
        cout << name << " doing work..." << endl;
    }
};

void level3() {
    ResourceHandler r3("Level3_Resource");
    cout << "Throwing exception from level 3..." << endl;
    throw runtime_error("Error at level 3");
}

void level2() {
    ResourceHandler r2("Level2_Resource");
    r2.doWork();
    level3();  // exception propagates from here
}

void level1() {
    ResourceHandler r1("Level1_Resource");
    r1.doWork();
    level2();
}

int main() {
    cout << "=== Starting exception handling demo ===" << endl;
    try {
        level1();
    }
    catch (const exception& e) {
        cout << "Exception caught in main: " << e.what() << endl;
    }
    cout << "=== Demo complete ===" << endl;
    return 0;
}
